UPDATE twork
SET wtitle = #{wtitle}, tcontent = #{tcontent}, tpublish = #{tpublish}, deadline = #{deadline}, scale = #{scale}
WHERE twid = #{twid}

mapper.select:
SELECT swid, scontent, correct, score, correction, tw.twid, tid, cid, wtitle, tcontent, tpublish, deadline, scale
FROM (
    SELECT twid, tid, cid, wtitle, tcontent, tpublish, deadline, scale
    FROM twork WHERE cid = #{cid}
) AS tw
LEFT JOIN (
    SELECT * FROM swork WHERE sid = (SELECT sid FROM student WHERE sphone = #{sid})
) AS sw ON tw.twid = sw.twid
